#include <bits/stdc++.h>
#define x first
#define y second
using namespace std;
typedef pair<double,int> PII;
typedef pair<double,PII> PIII;

const int N=5003,M=4e5+10;

int n,m,cnt[N];
int head[N],rh[N],ver[M],nxt[M],tot;
double edge[M],dis[N],sum[N],e;
bool b[N];

void add(int u,int v,double w){
    ver[++tot]=v,nxt[tot]=head[u],edge[tot]=w,head[u]=tot;
    ver[++tot]=u,nxt[tot]=rh[v],edge[tot]=w,rh[v]=tot;
}

int Astar(){
    priority_queue<PIII,vector<PIII>,greater<PIII>> q;
    q.push(make_pair(dis[1],make_pair(0,1)));
    while(q.size()){
        PIII x=q.top();
        q.pop();
        cnt[x.y.y]++;
        sum[x.y.y]+=x.y.x;
        if(x.y.y==n && sum[n]>e)
            return cnt[n]-1;
        if(x.y.y==n)
            continue;
        for(int i=head[x.y.y];i;i=nxt[i])
            q.push(make_pair(x.y.x+edge[i]+dis[ver[i]],make_pair(x.y.x+edge[i],ver[i])));
    }
    return cnt[n];
}

void Dijkstra(){
    priority_queue<PII,vector<PII>,greater<PII>> q;
    memset(dis,0x7f,sizeof(dis));
    dis[n]=0;
    q.push(make_pair(0,n));
    while(q.size()){
        while(q.size() && b[q.top().y])
            q.pop();
        if(q.empty())
            break;
        int x=q.top().y;
        b[x]=1,q.pop();
        for(int i=rh[x],y;i;i=nxt[i])
            if(dis[y=ver[i]]>dis[x]+edge[i]){
                dis[y]=dis[x]+edge[i];
                q.push(make_pair(dis[y],y));
            }
    }
}

int main(){
    scanf("%d%d%lf",&n,&m,&e);
    for(int i=1,u,v;i<=m;i++){
        double w;
        scanf("%d%d%lf",&u,&v,&w);
        add(u,v,w);
    }
    Dijkstra();
    printf("%d",Astar());
    return 0;
}
